function generatePlanStructure(hours, profession, needsSafety) {
  const config = {
    256: {modules: 8, practicals: 8},
    512: {modules: 10, practicals: 10},
    1100: {modules: 16, practicals: 22,submodules: {"11-16": 2}},
    1600: {modules: 20, practicals: 34,submodules: {"11-16": 2, "17-20": 3}},
    2048: {modules: 22, practicals: 46,submodules: {"11-16": 2, "17-20": 3, "21-22": 4}}
  }[hours];

  const modules = [];
  let availableHours = hours;

  // Модуль 1 - вводный
  modules.push({ number: 1, type: "introduction", hours: null, submodules: null });

  // Модуль 2 - безопасность
  if (needsSafety) {
    modules.push({ number: 2, type: "safety", hours: 16, submodules: null });
    availableHours -= 16;
  }

  // Остальные модули
  const startFrom = needsSafety ? 3 : 2;
  for (let i = startFrom; i <= config.modules; i++) {
    let submodules = null;
    if (config.submodules) {
      for (let [range, count] of Object.entries(config.submodules)) {
        const [start, end] = range.split('-').map(Number);
        if (i >= start && i <= end) {
          submodules = [];
          for (let j = 1; j <= count; j++) {
            submodules.push({ number: `${i}.${j}`, type: "content" });
          }
          break;
        }
      }
    }
    modules.push({ number: i, type: "content", hours: null, submodules });
  }

  return {
    hours,
    available_hours: availableHours,
    modules,
    total_practicals: config.practicals,
  };
}

// 🔹 Берём все входные items
const items = $input.all();

// 🔹 Обрабатываем каждый item
const results = items.map(item => {
  const { hours, profession, needsSafety } = item.json;
  return {
    json: generatePlanStructure(hours, profession, needsSafety)
  };
});

return results;

