const generatePlanStructure = (hours, profession, needsSafety) => {
  const configs = {
    256: {
      modules: 8,
      hours_per_module: [28, 32, 32, 32, 28, 32, 32, 28],
      attestation: 12,
      practicals: 8,
      literature: 8
    },
    512: {
      modules: 10,
      hours_per_module: [46, 46, 46, 46, 46, 46, 56, 56, 56, 56],
      attestation: 12,
      practicals: 10,
      literature: 10
    },
    1100: {
      modules: 16,
      hours_per_module: [50,50,50,50,50,50, 60,60,60,60, 90,90,90,90,90,90],
      attestation: 20,
      practicals: 22,
      literature: 15,
      submodules: {"11-16": 2}
    },
    1600: {
      modules: 20,
      hours_per_module: [50,50,50,50,50,50, 60,60,60,60, 100,100,100,100,100,100, 110,110,110,110],
      attestation: 20,
      practicals: 34,
      literature: 15,
      submodules: {"11-16": 2, "17-20": 3}
    },
    2048: {
      modules: 22,
      hours_per_module: [52,52,52,52,52,52, 64,64,64,64, 110,110,110,110,110,110, 120,120,120,120, 160,160],
      attestation: 20,
      practicals: 46,
      literature: 15,
      submodules: {"11-16": 2, "17-20": 3, "21-22": 4}
    }
  };

  const config = configs[hours];
  if (!config) throw new Error(`Неподдерживаемое количество часов: ${hours}`);

  const template_fields = ["Название_профессии"];

  for (let i = 1; i <= config.modules; i++) {
    template_fields.push(`модуль-${i}`);
  }

  if (config.submodules) {
    for (let [range, count] of Object.entries(config.submodules)) {
      const [start, end] = range.split('-').map(Number);
      for (let i = start; i <= end; i++) {
        for (let j = 1; j <= count; j++) {
          template_fields.push(`м${i}-подмодуль-${j}`);
        }
      }
    }
  }

  // Возвращаем массив с одним объектом для N8N
  return [{
    json: {
      hours: hours,
      profession: profession,
      module_count: config.modules,
      has_safety: needsSafety,
      hours_per_module: config.hours_per_module,
      attestation: config.attestation,
      submodules: config.submodules || null,
      template_fields: template_fields,
      practicals: config.practicals,
      literature: config.literature
    }
  }];
};

